// Package eightball is a Magic 8-Ball realm: ask a yes/no question and the
// block height decides your fate. Deterministic (no real randomness on-chain).
package eightball

import (
	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"
	"strconv"
	"strings"
)

// The 20 classic Magic 8-Ball answers.
var answers = []string{
	"It is certain.", "It is decidedly so.", "Without a doubt.",
	"Yes definitely.", "You may rely on it.", "As I see it, yes.",
	"Most likely.", "Outlook good.", "Yes.", "Signs point to yes.",
	"Reply hazy, try again.", "Ask again later.", "Better not tell you now.",
	"Cannot predict now.", "Concentrate and ask again.",
	"Don't count on it.", "My reply is no.", "My sources say no.",
	"Outlook not so good.", "Very doubtful.",
}

type shake struct {
	asker    string
	question string
	answer   string
	height   int64
}

var history []shake

// answerIndex maps (block height, prior shakes) to an answer slot. Pure and
// deterministic so it can be tested without touching realm state.
func answerIndex(height int64, n int) int {
	i := (height + int64(n)) % int64(len(answers))
	if i < 0 {
		i += int64(len(answers))
	}
	return int(i)
}

// Ask poses a question to the Magic 8-Ball and returns its answer. Crossing
// function: it mutates persistent state, so it takes `cur realm` (gno 0.9).
func Ask(cur realm, question string) string {
	question = strings.TrimSpace(question)
	if question == "" {
		panic("question must not be empty")
	}
	if len(question) > 200 {
		panic("question too long (max 200 chars)")
	}
	h := runtime.ChainHeight()
	ans := answers[answerIndex(h, len(history))]
	history = append(history, shake{
		asker:    unsafe.PreviousRealm().Address().String(),
		question: question,
		answer:   ans,
		height:   h,
	})
	chain.Emit("Shaken", "answer", ans, "height", strconv.FormatInt(h, 10))
	return ans
}

// Asked returns how many questions have been asked. Read-only.
func Asked() int { return len(history) }

// Render is the gnoweb Markdown view.
func Render(path string) string {
	var b strings.Builder
	b.WriteString("# 🎱 Magic 8-Ball\n\n")
	b.WriteString("> ⚠️ Experimental, auto-generated with no human supervision (MCP test corpus). ")
	b.WriteString("Not audited. See [r/moul/x/daily](https://github.com/moul/gno-contracts/blob/main/r/moul/x/daily/README.md).\n\n")
	b.WriteString("Ask a yes/no question — the block height decides your fate.\n\n")
	b.WriteString("**Questions asked:** ")
	b.WriteString(strconv.Itoa(len(history)))
	b.WriteString("\n\n")

	if len(history) == 0 {
		b.WriteString("_No questions yet. Call `Ask(\"will it rain tomorrow?\")`._\n")
		return b.String()
	}

	last := history[len(history)-1]
	b.WriteString("Last shake: 🎱 _")
	b.WriteString(last.answer)
	b.WriteString("_\n\n| # | asker | question | answer | height |\n")
	b.WriteString("|---|---|---|---|---|\n")

	start := len(history) - 1
	end := start - 14
	if end < 0 {
		end = 0
	}
	for i := start; i >= end; i-- {
		e := history[i]
		b.WriteString("| ")
		b.WriteString(strconv.Itoa(i + 1))
		b.WriteString(" | ")
		b.WriteString(shortAddr(e.asker))
		b.WriteString(" | ")
		b.WriteString(e.question)
		b.WriteString(" | ")
		b.WriteString(e.answer)
		b.WriteString(" | ")
		b.WriteString(strconv.FormatInt(e.height, 10))
		b.WriteString(" |\n")
	}
	return b.String()
}

func shortAddr(a string) string {
	if len(a) <= 13 {
		return a
	}
	return a[:8] + "…" + a[len(a)-4:]
}

// Package eggling is an on-chain egg incubator and creature collector.
// Plant an egg, let it incubate for a minimum number of blocks, then Hatch
// it: the longer you waited (and a little luck, seeded from the egg's own
// history) decides the rarity of the creature you get. Train hatched
// creatures to level them up. Unlike a tamagotchi there's nothing to feed
// or lose to neglect — eggling is about patience and the luck of the
// hatch, not survival.
package eggling

import (
	"crypto/sha256"
	"encoding/hex"
	"sort"
	"strconv"
	"strings"

	"chain/runtime"

	"gno.land/p/nt/avl/v0"
)

// minIncubation is the minimum number of blocks an egg must sit before it
// can hatch.
const minIncubation int64 = 20

// waitCap is the incubation-time bonus cap (in blocks) used by rarityTier,
// so waiting forever doesn't guarantee a legendary — it just improves odds.
const waitCap int64 = 200

var speciesNames = [...]string{
	"Slime", "Sprout", "Ember", "Pebble", "Breeze", "Glimmer", "Shade", "Coral",
}

var rarityNames = [...]string{"Common", "Uncommon", "Rare", "Legendary"}
var rarityEmoji = [...]string{"⚪", "🟢", "🔵", "🟡"}

// egg is the persisted record for one planted egg, hatched or not.
type egg struct {
	ID         string
	Owner      address
	PlantedAt  int64
	Hatched    bool
	Species    string
	RarityTier int
	Name       string
	XP         int
	Level      int
}

var (
	eggs         avl.Tree // id string -> *egg
	nextID       int
	totalPlanted int
	totalHatched int
	rarityCounts [4]int
)

func get(id string) (*egg, bool) {
	v := eggs.Get(id)
	if v == nil {
		return nil, false
	}
	return v.(*egg), true
}

// hashSeed hashes the given parts (joined with ":") to a deterministic hex
// digest. Used to derive an egg's species and rarity roll from facts
// already fixed at plant time, so nobody — not even the owner — can game
// the outcome after the fact.
func hashSeed(parts ...string) string {
	sum := sha256.Sum256([]byte(strings.Join(parts, ":")))
	return hex.EncodeToString(sum[:])
}

// seedBytes pulls the first two bytes out of a hex digest for use as two
// independent 0-255 rolls (species pick, rarity roll).
func seedBytes(seedHex string) (byte, byte) {
	raw, err := hex.DecodeString(seedHex)
	if err != nil || len(raw) < 2 {
		return 0, 0
	}
	return raw[0], raw[1]
}

// rarityTier turns a 0-255 roll plus the blocks waited into a tier index
// 0..3 (common..legendary). Waiting longer raises the effective score, so
// patience improves your odds, but a bad roll can still land common even
// after a long wait, and a lucky roll can hatch rare almost immediately.
func rarityTier(roll uint8, waitBlocks int64) int {
	bonus := waitBlocks
	if bonus > waitCap {
		bonus = waitCap
	}
	score := int(roll) + int(bonus)/2
	switch {
	case score >= 300:
		return 3
	case score >= 220:
		return 2
	case score >= 140:
		return 1
	default:
		return 0
	}
}

// plant is the non-crossing core of PlantEgg.
func plant(owner address, height int64) *egg {
	nextID++
	id := strconv.Itoa(nextID)
	e := &egg{ID: id, Owner: owner, PlantedAt: height}
	eggs.Set(id, e)
	totalPlanted++
	return e
}

// PlantEgg starts incubating a new egg for the caller. Returns its ID.
func PlantEgg(cur realm) string {
	if !cur.IsCurrent() {
		panic("spoofed realm")
	}
	e := plant(cur.Previous().Address(), runtime.ChainHeight())
	return "🥚 planted egg #" + e.ID + " — incubate at least " +
		strconv.Itoa(int(minIncubation)) + " blocks, then Hatch(\"" + e.ID + "\")"
}

// hatch is the non-crossing core of Hatch.
func hatch(e *egg, height int64) string {
	if e.Hatched {
		panic("egg #" + e.ID + " already hatched into a " + e.Species)
	}
	wait := height - e.PlantedAt
	if wait < minIncubation {
		panic("egg #" + e.ID + " needs " + strconv.Itoa(int(minIncubation-wait)) + " more blocks to incubate")
	}

	seed := hashSeed(e.ID, e.Owner.String(), strconv.FormatInt(e.PlantedAt, 10))
	rarityRoll, speciesRoll := seedBytes(seed)
	tier := rarityTier(rarityRoll, wait)
	species := speciesNames[int(speciesRoll)%len(speciesNames)]

	e.Hatched = true
	e.Species = species
	e.RarityTier = tier
	e.Name = species
	e.Level = 1
	rarityCounts[tier]++
	totalHatched++

	return rarityEmoji[tier] + " egg #" + e.ID + " hatched into a " + rarityNames[tier] + " " + species + "!"
}

// Hatch hatches an incubated egg the caller owns.
func Hatch(cur realm, id string) string {
	if !cur.IsCurrent() {
		panic("spoofed realm")
	}
	e, ok := get(id)
	if !ok {
		panic("no such egg #" + id)
	}
	if e.Owner != cur.Previous().Address() {
		panic("only the owner can hatch egg #" + id)
	}
	return hatch(e, runtime.ChainHeight())
}

// train is the non-crossing core of Train.
func train(e *egg) string {
	if !e.Hatched {
		panic("egg #" + e.ID + " hasn't hatched yet")
	}
	e.XP += 10
	newLevel := e.XP/50 + 1
	leveled := newLevel > e.Level
	e.Level = newLevel

	msg := e.Name + " gained 10 XP (" + strconv.Itoa(e.XP) + " total)"
	if leveled {
		msg += " and reached level " + strconv.Itoa(e.Level) + "!"
	}
	return msg
}

// Train gives a hatched creature the caller owns some experience, leveling
// it up every 50 XP.
func Train(cur realm, id string) string {
	if !cur.IsCurrent() {
		panic("spoofed realm")
	}
	e, ok := get(id)
	if !ok {
		panic("no such egg #" + id)
	}
	if e.Owner != cur.Previous().Address() {
		panic("only the owner can train egg #" + id)
	}
	return train(e)
}

// rename is the non-crossing core of Rename.
func rename(e *egg, name string) string {
	if !e.Hatched {
		panic("egg #" + e.ID + " hasn't hatched yet — nothing to name")
	}
	name = strings.TrimSpace(name)
	if name == "" {
		panic("name cannot be empty")
	}
	old := e.Name
	e.Name = name
	return old + " renamed to " + name
}

// Rename gives a hatched creature the caller owns a custom name.
func Rename(cur realm, id string, name string) string {
	if !cur.IsCurrent() {
		panic("spoofed realm")
	}
	e, ok := get(id)
	if !ok {
		panic("no such egg #" + id)
	}
	if e.Owner != cur.Previous().Address() {
		panic("only the owner can rename egg #" + id)
	}
	return rename(e, name)
}

// escapeInline neutralizes markdown-active characters in untrusted text
// before it's embedded inline in Render output.
func escapeInline(s string) string {
	r := strings.NewReplacer(
		"\\", "\\\\",
		"`", "\\`",
		"*", "\\*",
		"_", "\\_",
		"[", "\\[",
		"]", "\\]",
		"|", "\\|",
	)
	return r.Replace(s)
}

func shortAddr(a address) string {
	s := a.String()
	if len(s) > 12 {
		return s[:8] + "…" + s[len(s)-4:]
	}
	return s
}

// byIDNumeric orders eggs by their numeric ID, ascending.
type byIDNumeric []*egg

func (r byIDNumeric) Len() int      { return len(r) }
func (r byIDNumeric) Swap(i, j int) { r[i], r[j] = r[j], r[i] }
func (r byIDNumeric) Less(i, j int) bool {
	a, _ := strconv.Atoi(r[i].ID)
	b, _ := strconv.Atoi(r[j].ID)
	return a < b
}

func allEggs() []*egg {
	var rows []*egg
	eggs.Iterate("", "", func(_ string, v any) bool {
		rows = append(rows, v.(*egg))
		return false
	})
	sort.Stable(byIDNumeric(rows))
	return rows
}

func renderHome() string {
	var b strings.Builder
	b.WriteString("# 🥚 Eggling\n\n")
	b.WriteString("An on-chain egg incubator. `PlantEgg()` to start one, wait at least " +
		strconv.Itoa(int(minIncubation)) + " blocks, then `Hatch(id)` — the longer you " +
		"waited (plus a little sealed-in luck) decides the rarity of the creature you get. " +
		"`Train(id)` levels a hatched creature up; `Rename(id, name)` gives it a name.\n\n")

	b.WriteString("- Eggs planted: " + strconv.Itoa(totalPlanted) + "\n")
	b.WriteString("- Creatures hatched: " + strconv.Itoa(totalHatched) + "\n")
	if totalHatched > 0 {
		for tier := 3; tier >= 0; tier-- {
			if rarityCounts[tier] > 0 {
				b.WriteString("  - " + rarityEmoji[tier] + " " + rarityNames[tier] + ": " +
					strconv.Itoa(rarityCounts[tier]) + "\n")
			}
		}
	}

	rows := allEggs()
	b.WriteString("\n## Eggs\n\n")
	if len(rows) == 0 {
		b.WriteString("_None planted yet. Be the first!_\n")
		return b.String()
	}

	b.WriteString("| ID | Owner | Status | Level |\n")
	b.WriteString("| :--- | :--- | :--- | ---: |\n")
	for _, e := range rows {
		status := "🥚 incubating"
		level := "-"
		if e.Hatched {
			status = rarityEmoji[e.RarityTier] + " " + escapeInline(e.Name) + " (" + rarityNames[e.RarityTier] + " " + e.Species + ")"
			level = strconv.Itoa(e.Level)
		}
		b.WriteString("| #" + e.ID + " | `" + shortAddr(e.Owner) + "` | " + status + " | " + level + " |\n")
	}
	b.WriteString("\n_View a single egg at this realm's path plus its ID (e.g. `.../eggling:3`), " +
		"or one owner's eggs plus their address._\n")
	return b.String()
}

func renderEgg(id string, height int64) string {
	e, ok := get(id)
	if !ok {
		return "# Egg #" + escapeInline(id) + "\n\nNo such egg.\n"
	}

	var b strings.Builder
	if !e.Hatched {
		wait := height - e.PlantedAt
		b.WriteString("# 🥚 Egg #" + e.ID + "\n\n")
		b.WriteString("- Owner: `" + e.Owner.String() + "`\n")
		b.WriteString("- Planted at block: " + strconv.FormatInt(e.PlantedAt, 10) + "\n")
		if wait < minIncubation {
			b.WriteString("- Ready to hatch in: " + strconv.FormatInt(minIncubation-wait, 10) + " more blocks\n")
		} else {
			b.WriteString("- Ready to hatch now — call `Hatch(\"" + e.ID + "\")`\n")
		}
		return b.String()
	}

	b.WriteString("# " + rarityEmoji[e.RarityTier] + " " + e.Name + "\n\n")
	b.WriteString("- Owner: `" + e.Owner.String() + "`\n")
	b.WriteString("- Species: " + e.Species + "\n")
	b.WriteString("- Rarity: " + rarityNames[e.RarityTier] + "\n")
	b.WriteString("- Level: " + strconv.Itoa(e.Level) + " (" + strconv.Itoa(e.XP) + " XP)\n")
	return b.String()
}

func renderOwner(rawAddr string) string {
	owner := address(strings.TrimSpace(rawAddr))
	safe := escapeInline(owner.String())

	var b strings.Builder
	b.WriteString("# Eggs owned by " + safe + "\n\n")

	found := false
	for _, e := range allEggs() {
		if e.Owner != owner {
			continue
		}
		found = true
		if e.Hatched {
			b.WriteString("- #" + e.ID + ": " + rarityEmoji[e.RarityTier] + " " + escapeInline(e.Name) +
				" — " + rarityNames[e.RarityTier] + " " + e.Species + ", level " + strconv.Itoa(e.Level) + "\n")
		} else {
			b.WriteString("- #" + e.ID + ": 🥚 incubating\n")
		}
	}
	if !found {
		b.WriteString("_No eggs found for this address._\n")
	}
	return b.String()
}

// Render shows the full egg list at "", a single egg's detail when path is
// a numeric ID, or one owner's eggs when path is a bech32 address.
func Render(path string) string {
	path = strings.TrimPrefix(strings.TrimSpace(path), "/")
	if path == "" {
		return renderHome()
	}
	if _, err := strconv.Atoi(path); err == nil {
		return renderEgg(path, runtime.ChainHeight())
	}
	return renderOwner(path)
}

// Package erc721 is an idiomatic gno.land port of the Solidity ERC-721
// non-fungible token standard. Each token has a unique integer id owned by
// exactly one address; ids are minted sequentially. Ownership, per-owner
// balances and single-token approvals are kept in ordered avl trees so that
// Render can iterate deterministically.
package erc721

import (
	"strconv"

	"chain"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

const (
	name   = "Gno NFT"
	symbol = "GNFT"
)

var (
	owners    avl.Tree // tokenID (zero-padded string) -> address
	balances  avl.Tree // owner address (string) -> uint64
	approvals avl.Tree // tokenID (zero-padded string) -> approved address
	nextID    int64    = 1
	minted    int64    // total tokens ever minted (== live supply, no burn)
)

// key formats a token id into a zero-padded, lexicographically-sortable key.
func key(id int64) string {
	s := strconv.FormatInt(id, 10)
	for len(s) < 12 {
		s = "0" + s
	}
	return s
}

// Mint creates the next token id and assigns it to `to`. Only sequential
// minting is supported (id is returned via the Mint event).
func Mint(cur realm, to address) int64 {
	if !to.IsValid() {
		panic("erc721: mint to invalid address")
	}
	id := nextID
	nextID++
	minted++

	owners.Set(key(id), to)
	balances.Set(to.String(), balanceOf(to)+1)

	chain.Emit("Mint", "to", to.String(), "tokenID", strconv.FormatInt(id, 10))
	return id
}

// Transfer moves token `id` from the caller to `to`. The caller must own the
// token (approvals are cleared on transfer).
func Transfer(cur realm, to address, id int64) {
	if !to.IsValid() {
		panic("erc721: transfer to invalid address")
	}
	caller := unsafe.PreviousRealm().Address()
	from := ownerOf(id) // panics if the token does not exist

	if caller != from {
		// allow the single-token approved operator too
		if approvedOf(id) != caller {
			panic("erc721: caller is neither owner nor approved")
		}
	}
	if from == to {
		panic("erc721: transfer to current owner")
	}

	owners.Set(key(id), to)
	balances.Set(from.String(), balanceOf(from)-1)
	balances.Set(to.String(), balanceOf(to)+1)
	approvals.Remove(key(id)) // clear approval on transfer

	chain.Emit("Transfer", "from", from.String(), "to", to.String(),
		"tokenID", strconv.FormatInt(id, 10))
}

// Approve grants `spender` the right to transfer token `id`. Only the current
// owner may approve.
func Approve(cur realm, spender address, id int64) {
	caller := unsafe.PreviousRealm().Address()
	owner := ownerOf(id)
	if caller != owner {
		panic("erc721: approve caller is not owner")
	}
	approvals.Set(key(id), spender)
	chain.Emit("Approval", "owner", owner.String(), "spender", spender.String(),
		"tokenID", strconv.FormatInt(id, 10))
}

// --- read-only helpers (safe to call from tests and Render) ---

// ownerOf returns the owner of token `id`, panicking if it does not exist.
func ownerOf(id int64) address {
	v := owners.Get(key(id))
	if v == nil {
		panic("erc721: query for nonexistent token")
	}
	return v.(address)
}

// approvedOf returns the approved address for token `id`, or the zero address.
func approvedOf(id int64) address {
	v := approvals.Get(key(id))
	if v == nil {
		return address("")
	}
	return v.(address)
}

// balanceOf returns how many tokens `owner` holds.
func balanceOf(owner address) uint64 {
	v := balances.Get(owner.String())
	if v == nil {
		return 0
	}
	return v.(uint64)
}

// exists reports whether token `id` has been minted (and not since moved away).
func exists(id int64) bool {
	return owners.Has(key(id))
}

// totalSupply returns the number of tokens in circulation.
func totalSupply() int64 { return minted }

// OwnerOf is the exported read-only accessor for ownerOf.
func OwnerOf(id int64) address { return ownerOf(id) }

// BalanceOf is the exported read-only accessor for balanceOf.
func BalanceOf(owner address) uint64 { return balanceOf(owner) }

// TotalSupply is the exported read-only accessor for totalSupply.
func TotalSupply() int64 { return totalSupply() }

// Render displays collection metadata and a token -> owner table.
func Render(path string) string {
	out := "# " + name + " (" + symbol + ")\n\n"
	out += "**Total supply:** " + strconv.FormatInt(totalSupply(), 10) + "\n\n"

	if owners.Size() == 0 {
		out += "_No tokens minted yet._\n"
		return out
	}

	out += "| Token ID | Owner | Approved |\n"
	out += "|---------:|-------|----------|\n"
	owners.Iterate("", "", func(k string, v interface{}) bool {
		owner := v.(address)
		id, _ := strconv.ParseInt(k, 10, 64)
		appr := approvedOf(id)
		apprStr := "—"
		if appr != address("") {
			apprStr = appr.String()
		}
		out += "| " + strconv.FormatInt(id, 10) + " | " +
			owner.String() + " | " + apprStr + " |\n"
		return false
	})
	return out
}

// Package erc1155 is an idiomatic gno.land port of the Solidity ERC-1155
// multi-token standard. A single realm tracks many distinct token ids, each
// with its own fungible balances. Balances are keyed by (owner, id) in an
// avl.Tree so Render can iterate deterministically.
package erc1155

import (
	"strconv"
	"strings"

	"chain"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

// balances maps "<owner>:<id>" -> uint64 amount.
var balances avl.Tree

// supply maps "<id>" -> uint64 total minted for that id.
var supply avl.Tree

func balKey(owner address, id int) string {
	return owner.String() + ":" + strconv.Itoa(id)
}

func supKey(id int) string {
	return strconv.Itoa(id)
}

func getBalance(owner address, id int) uint64 {
	k := balKey(owner, id)
	if !balances.Has(k) {
		return 0
	}
	return balances.Get(k).(uint64)
}

func setBalance(owner address, id int, amount uint64) {
	k := balKey(owner, id)
	if amount == 0 {
		balances.Remove(k)
		return
	}
	balances.Set(k, amount)
}

func getSupply(id int) uint64 {
	k := supKey(id)
	if !supply.Has(k) {
		return 0
	}
	return supply.Get(k).(uint64)
}

// Mint creates `amount` units of token `id` and credits them to `to`.
func Mint(cur realm, to address, id int, amount uint64) {
	if !to.IsValid() {
		panic("erc1155: mint to invalid address")
	}
	if amount == 0 {
		panic("erc1155: mint amount must be > 0")
	}
	setBalance(to, id, getBalance(to, id)+amount)
	supply.Set(supKey(id), getSupply(id)+amount)

	operator := unsafe.PreviousRealm().Address()
	chain.Emit("Mint",
		"operator", operator.String(),
		"to", to.String(),
		"id", strconv.Itoa(id),
		"amount", strconv.FormatUint(amount, 10),
	)
}

// TransferSingle moves `amount` of token `id` from the caller to `to`.
func TransferSingle(cur realm, to address, id int, amount uint64) {
	if !to.IsValid() {
		panic("erc1155: transfer to invalid address")
	}
	if amount == 0 {
		panic("erc1155: transfer amount must be > 0")
	}
	from := unsafe.PreviousRealm().Address()
	fromBal := getBalance(from, id)
	if fromBal < amount {
		panic("erc1155: insufficient balance")
	}
	setBalance(from, id, fromBal-amount)
	setBalance(to, id, getBalance(to, id)+amount)

	chain.Emit("TransferSingle",
		"from", from.String(),
		"to", to.String(),
		"id", strconv.Itoa(id),
		"amount", strconv.FormatUint(amount, 10),
	)
}

// BalanceOf returns the amount of token `id` held by `owner`.
func BalanceOf(owner address, id int) uint64 {
	return getBalance(owner, id)
}

// TotalSupply returns the total amount minted of token `id`.
func TotalSupply(id int) uint64 {
	return getSupply(id)
}

// Render prints a balances table and a per-id supply table.
func Render(path string) string {
	var b strings.Builder
	b.WriteString("# ERC-1155 Multi-Token\n\n")
	b.WriteString("A single realm holding many fungible token ids. ")
	b.WriteString("Balances are keyed by `(owner, id)`.\n\n")

	b.WriteString("## Balances\n\n")
	if balances.Size() == 0 {
		b.WriteString("_No balances yet. Call `Mint` to create tokens._\n\n")
	} else {
		b.WriteString("| Owner | ID | Amount |\n")
		b.WriteString("|---|---|---|\n")
		balances.Iterate("", "", func(key string, value interface{}) bool {
			owner, id := splitBalKey(key)
			b.WriteString("| `" + owner + "` | " + id + " | " +
				strconv.FormatUint(value.(uint64), 10) + " |\n")
			return false
		})
		b.WriteString("\n")
	}

	b.WriteString("## Supply per ID\n\n")
	if supply.Size() == 0 {
		b.WriteString("_No tokens minted._\n")
	} else {
		b.WriteString("| ID | Total Supply |\n")
		b.WriteString("|---|---|\n")
		supply.Iterate("", "", func(key string, value interface{}) bool {
			b.WriteString("| " + key + " | " +
				strconv.FormatUint(value.(uint64), 10) + " |\n")
			return false
		})
	}

	return b.String()
}

// splitBalKey splits a "<owner>:<id>" balance key. The owner (a bech32
// address) contains no ':', so the id is the substring after the last ':'.
func splitBalKey(key string) (owner, id string) {
	i := strings.LastIndex(key, ":")
	if i < 0 {
		return key, ""
	}
	return key[:i], key[i+1:]
}

// Package crowdfund is an accounting-only port of the classic Solidity
// Kickstarter-style crowdfunding contract to a gno.land realm.
//
// A creator Launches a campaign with a funding goal and a duration (in blocks).
// Backers Pledge (and may Unpledge before the deadline). After the deadline the
// creator can Claim if the goal was met, otherwise backers can Refund.
//
// No real coin moves: pledges are tracked as plain uint64 accounting, exactly
// like the mapping(address => uint) balances of the Solidity original.
package crowdfund

import (
	"strconv"

	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

// Campaign holds the state of a single crowdfunding campaign.
type Campaign struct {
	ID       int
	Creator  address
	Goal     uint64
	Deadline int64     // block height after which the campaign is closed
	Pledged  uint64    // running total pledged
	Claimed  bool      // creator already claimed the funds
	pledges  *avl.Tree // backer address (string) -> pledged uint64
}

var (
	campaigns = avl.NewTree() // padded id -> *Campaign (ordered by id)
	nextID    = 1
)

// key zero-pads an id so avl iteration is in numeric order.
func key(id int) string {
	s := strconv.Itoa(id)
	for len(s) < 12 {
		s = "0" + s
	}
	return s
}

func mustGet(id int) *Campaign {
	v := campaigns.Get(key(id))
	if v == nil {
		panic("campaign not found")
	}
	return v.(*Campaign)
}

// Launch creates a new campaign owned by the caller and returns its id.
func Launch(cur realm, goal uint64, durationBlocks int) int {
	if goal == 0 {
		panic("goal must be > 0")
	}
	if durationBlocks <= 0 {
		panic("duration must be > 0")
	}
	caller := unsafe.PreviousRealm().Address()
	id := nextID
	nextID++
	c := &Campaign{
		ID:       id,
		Creator:  caller,
		Goal:     goal,
		Deadline: runtime.ChainHeight() + int64(durationBlocks),
		pledges:  avl.NewTree(),
	}
	campaigns.Set(key(id), c)
	chain.Emit("Launch",
		"id", strconv.Itoa(id),
		"creator", caller.String(),
		"goal", strconv.FormatUint(goal, 10))
	return id
}

// Pledge backs campaign id with amount (before the deadline).
func Pledge(cur realm, id int, amount uint64) {
	if amount == 0 {
		panic("amount must be > 0")
	}
	c := mustGet(id)
	if runtime.ChainHeight() > c.Deadline {
		panic("campaign ended")
	}
	caller := unsafe.PreviousRealm().Address()
	prev := uint64(0)
	if v := c.pledges.Get(caller.String()); v != nil {
		prev = v.(uint64)
	}
	c.pledges.Set(caller.String(), prev+amount)
	c.Pledged += amount
	chain.Emit("Pledge",
		"id", strconv.Itoa(id),
		"from", caller.String(),
		"amount", strconv.FormatUint(amount, 10))
}

// Unpledge withdraws amount from the caller's pledge (before the deadline).
func Unpledge(cur realm, id int, amount uint64) {
	if amount == 0 {
		panic("amount must be > 0")
	}
	c := mustGet(id)
	if runtime.ChainHeight() > c.Deadline {
		panic("campaign ended")
	}
	caller := unsafe.PreviousRealm().Address()
	v := c.pledges.Get(caller.String())
	if v == nil {
		panic("nothing pledged")
	}
	have := v.(uint64)
	if amount > have {
		panic("amount exceeds pledge")
	}
	if remaining := have - amount; remaining == 0 {
		c.pledges.Remove(caller.String())
	} else {
		c.pledges.Set(caller.String(), remaining)
	}
	c.Pledged -= amount
	chain.Emit("Unpledge",
		"id", strconv.Itoa(id),
		"from", caller.String(),
		"amount", strconv.FormatUint(amount, 10))
}

// Claim lets the creator take the funds if the goal was met after the deadline.
func Claim(cur realm, id int) {
	c := mustGet(id)
	if runtime.ChainHeight() <= c.Deadline {
		panic("campaign not ended")
	}
	caller := unsafe.PreviousRealm().Address()
	if caller != c.Creator {
		panic("only creator can claim")
	}
	if c.Pledged < c.Goal {
		panic("goal not reached")
	}
	if c.Claimed {
		panic("already claimed")
	}
	c.Claimed = true
	chain.Emit("Claim",
		"id", strconv.Itoa(id),
		"amount", strconv.FormatUint(c.Pledged, 10))
}

// Refund returns the caller's pledge if the campaign failed after the deadline.
func Refund(cur realm, id int) {
	c := mustGet(id)
	if runtime.ChainHeight() <= c.Deadline {
		panic("campaign not ended")
	}
	if c.Pledged >= c.Goal {
		panic("campaign succeeded, no refund")
	}
	caller := unsafe.PreviousRealm().Address()
	v := c.pledges.Get(caller.String())
	if v == nil {
		panic("nothing to refund")
	}
	amount := v.(uint64)
	c.pledges.Remove(caller.String())
	c.Pledged -= amount
	chain.Emit("Refund",
		"id", strconv.Itoa(id),
		"to", caller.String(),
		"amount", strconv.FormatUint(amount, 10))
}

// --- pure/read-only helpers (also used by Render) ---

// pct returns the funded percentage (0..100).
func pct(pledged, goal uint64) int {
	if goal == 0 {
		return 0
	}
	p := int(pledged * 100 / goal)
	if p > 100 {
		p = 100
	}
	return p
}

// progressBar renders a fixed-width ▓░ bar for pledged/goal.
func progressBar(pledged, goal uint64) string {
	const width = 20
	filled := 0
	if goal > 0 {
		filled = int(pledged * width / goal)
		if filled > width {
			filled = width
		}
	}
	bar := ""
	for i := 0; i < width; i++ {
		if i < filled {
			bar += "▓"
		} else {
			bar += "░"
		}
	}
	return bar
}

// state describes a campaign relative to a given block height.
func state(c *Campaign, height int64) string {
	if height <= c.Deadline {
		return "Active"
	}
	if c.Pledged >= c.Goal {
		if c.Claimed {
			return "Funded (claimed)"
		}
		return "Funded"
	}
	return "Failed"
}

// Render shows all campaigns with a progress bar, goal, pledged and state.
func Render(path string) string {
	if campaigns.Size() == 0 {
		return "# Crowdfund\n\nNo campaigns yet. Call `Launch(goal, durationBlocks)` to start one.\n"
	}
	height := runtime.ChainHeight()
	out := "# Crowdfund\n\n"
	out += "Current block height: **" + strconv.FormatInt(height, 10) + "**\n\n"
	campaigns.Iterate("", "", func(k string, v any) bool {
		c := v.(*Campaign)
		out += "## Campaign #" + strconv.Itoa(c.ID) + "\n\n"
		out += "`" + progressBar(c.Pledged, c.Goal) + "` " + strconv.Itoa(pct(c.Pledged, c.Goal)) + "%\n\n"
		out += "- State: **" + state(c, height) + "**\n"
		out += "- Goal: " + strconv.FormatUint(c.Goal, 10) + "\n"
		out += "- Pledged: " + strconv.FormatUint(c.Pledged, 10) + "\n"
		out += "- Deadline: block " + strconv.FormatInt(c.Deadline, 10) + "\n"
		out += "- Creator: `" + c.Creator.String() + "`\n\n"
		return false
	})
	return out
}

// Package timelock is a simplified port of OpenZeppelin's TimelockController.
//
// Operations are scheduled with a delay (measured in blocks). A scheduled
// operation becomes executable only once the chain height reaches the
// operation's ready height. Until then it can be cancelled by anyone (this
// simplified port omits role-based access control). Once executed or
// cancelled, an operation is terminal.
//
// Solidity mapping:
//   - block.number      -> runtime.ChainHeight()
//   - msg.sender        -> unsafe.PreviousRealm().Address()
//   - require(...)       -> panic(...)
//   - events            -> chain.Emit(...)
//   - mapping(id => op) -> avl.Tree keyed by zero-padded id
package timelock

import (
	"strconv"

	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"
)

// State labels for an operation.
const (
	StatePending   = "Pending"   // scheduled, not yet ready
	StateReady     = "Ready"     // ready height reached, awaiting execution
	StateExecuted  = "Executed"  // terminal
	StateCancelled = "Cancelled" // terminal
)

// Operation is a single scheduled action.
type Operation struct {
	ID          int
	Action      string
	Proposer    address
	Scheduled   int64 // chain height at scheduling
	ReadyHeight int64 // executable once ChainHeight() >= ReadyHeight
	Done        bool  // executed
	Cancelled   bool
}

var (
	ops    = avl.NewTree() // key: paddedKey(id) -> *Operation
	nextID = 1
)

// Schedule registers a new operation to run after delayBlocks blocks and
// returns its id. delayBlocks must be >= 0.
func Schedule(cur realm, action string, delayBlocks int) int {
	if action == "" {
		panic("timelock: empty action")
	}
	if delayBlocks < 0 {
		panic("timelock: negative delay")
	}

	h := runtime.ChainHeight()
	id := nextID
	nextID++

	op := &Operation{
		ID:          id,
		Action:      action,
		Proposer:    unsafe.PreviousRealm().Address(),
		Scheduled:   h,
		ReadyHeight: h + int64(delayBlocks),
	}
	ops.Set(paddedKey(id), op)

	chain.Emit("Scheduled",
		"id", strconv.Itoa(id),
		"action", action,
		"readyHeight", strconv.FormatInt(op.ReadyHeight, 10),
	)
	return id
}

// Execute runs a ready operation. It panics if the operation is unknown,
// already terminal, or not yet ready.
func Execute(cur realm, id int) {
	op := mustGet(id)
	if op.Done {
		panic("timelock: already executed")
	}
	if op.Cancelled {
		panic("timelock: operation cancelled")
	}
	if runtime.ChainHeight() < op.ReadyHeight {
		panic("timelock: operation not ready")
	}
	op.Done = true

	chain.Emit("Executed", "id", strconv.Itoa(id), "action", op.Action)
}

// Cancel drops a pending or ready operation before it executes. It panics if
// the operation is unknown or already terminal.
func Cancel(cur realm, id int) {
	op := mustGet(id)
	if op.Done {
		panic("timelock: already executed")
	}
	if op.Cancelled {
		panic("timelock: already cancelled")
	}
	op.Cancelled = true

	chain.Emit("Cancelled", "id", strconv.Itoa(id), "action", op.Action)
}

// mustGet returns the operation or panics if absent.
func mustGet(id int) *Operation {
	v := ops.Get(paddedKey(id))
	if v == nil {
		panic("timelock: unknown operation")
	}
	return v.(*Operation)
}

// --- pure/read-only helpers (safe to unit-test) ---

// paddedKey returns a fixed-width, lexicographically sortable key for an id so
// avl iteration yields operations in id order.
func paddedKey(id int) string {
	s := strconv.Itoa(id)
	for len(s) < 12 {
		s = "0" + s
	}
	return s
}

// StateOf returns the display state of op at the given chain height.
func StateOf(op *Operation, height int64) string {
	switch {
	case op.Cancelled:
		return StateCancelled
	case op.Done:
		return StateExecuted
	case height >= op.ReadyHeight:
		return StateReady
	default:
		return StatePending
	}
}

// BlocksRemaining returns how many blocks remain before op is ready (0 if
// already ready or past).
func BlocksRemaining(op *Operation, height int64) int64 {
	if height >= op.ReadyHeight {
		return 0
	}
	return op.ReadyHeight - height
}

// Render implements the standard realm markdown view.
func Render(path string) string {
	h := runtime.ChainHeight()
	out := "# Timelock Controller\n\n"
	out += ufmt.Sprintf("Current chain height: **%d**\n\n", h)

	if ops.Size() == 0 {
		out += "_No operations scheduled yet._\n\n"
		out += "Call `Schedule(action, delayBlocks)` to queue one.\n"
		return out
	}

	out += ufmt.Sprintf("Total operations: **%d**\n\n", ops.Size())
	out += "| ID | Action | State | Ready @ | Blocks left | Proposer |\n"
	out += "|---:|--------|-------|--------:|------------:|----------|\n"

	ops.Iterate("", "", func(_ string, v any) bool {
		op := v.(*Operation)
		state := StateOf(op, h)
		left := BlocksRemaining(op, h)
		out += ufmt.Sprintf("| %d | %s | %s | %d | %d | %s |\n",
			op.ID, op.Action, state, op.ReadyHeight, left, op.Proposer.String())
		return false
	})
	return out
}

// Package staking is a simplified, accounting-only port of Synthetix
// StakingRewards to gno.land. Users stake a fungible amount; rewards accrue
// every block, proportional to each staker's share of the total staked,
// at a fixed rewardPerBlock. There is no real coin transfer — balances and
// rewards are plain uint64 accounting (a demonstration of the classic
// "reward-per-token" accumulator pattern).
package staking

import (
	"strconv"

	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

const (
	// rewardPerBlock is the fixed number of reward units distributed across
	// ALL stakers on every block, split by stake share.
	rewardPerBlock = uint64(100)
	// precision scales the reward-per-token accumulator to avoid truncation.
	precision = uint64(1_000_000)
)

type account struct {
	staked     uint64 // currently staked amount
	rewardPaid uint64 // reward-per-token snapshot at the account's last update
	reward     uint64 // accrued-but-unclaimed rewards
	minted     uint64 // rewards moved into the caller's reward balance
}

var (
	accounts          avl.Tree // address string -> *account
	totalStaked       uint64
	rewardPerTokenAcc uint64 // global accumulator, scaled by precision
	lastUpdateBlock   uint64
)

// --- pure helpers (unit-tested) ------------------------------------------

// computeRewardPerToken advances the accumulator by the rewards earned per
// staked unit over `elapsed` blocks. With no stake, the accumulator is frozen.
func computeRewardPerToken(stored, rate, elapsed, total uint64) uint64 {
	if total == 0 {
		return stored
	}
	return stored + (rate*elapsed*precision)/total
}

// computeEarned returns total rewards owed to an account given its stake, the
// current accumulator, the accumulator value already paid, and prior accrual.
func computeEarned(balance, rptCurrent, rptPaid, accrued uint64) uint64 {
	return accrued + (balance*(rptCurrent-rptPaid))/precision
}

// --- internals ------------------------------------------------------------

func currentBlock() uint64 { return uint64(runtime.ChainHeight()) }

func getOrCreate(addr string) *account {
	if v := accounts.Get(addr); v != nil {
		return v.(*account)
	}
	acc := &account{}
	accounts.Set(addr, acc)
	return acc
}

// accrue rolls the global accumulator forward to the current block and folds
// the caller's freshly-earned rewards into its stored balance. Mirrors the
// Synthetix `updateReward(account)` modifier.
func accrue(addr string) *account {
	elapsed := currentBlock() - lastUpdateBlock
	rewardPerTokenAcc = computeRewardPerToken(rewardPerTokenAcc, rewardPerBlock, elapsed, totalStaked)
	lastUpdateBlock = currentBlock()

	acc := getOrCreate(addr)
	acc.reward = computeEarned(acc.staked, rewardPerTokenAcc, acc.rewardPaid, acc.reward)
	acc.rewardPaid = rewardPerTokenAcc
	return acc
}

// --- exported transactions (crossing) ------------------------------------

// Stake adds `amount` to the caller's staked balance.
func Stake(cur realm, amount uint64) {
	if amount == 0 {
		panic("staking: amount must be > 0")
	}
	addr := unsafe.PreviousRealm().Address().String()
	acc := accrue(addr)
	acc.staked += amount
	totalStaked += amount
	chain.Emit("Staked", "addr", addr, "amount", strconv.FormatUint(amount, 10))
}

// Withdraw removes `amount` from the caller's staked balance.
func Withdraw(cur realm, amount uint64) {
	if amount == 0 {
		panic("staking: amount must be > 0")
	}
	addr := unsafe.PreviousRealm().Address().String()
	acc := accrue(addr)
	if amount > acc.staked {
		panic("staking: insufficient staked balance")
	}
	acc.staked -= amount
	totalStaked -= amount
	chain.Emit("Withdrawn", "addr", addr, "amount", strconv.FormatUint(amount, 10))
}

// GetReward mints all accrued rewards into the caller's reward balance and
// resets the accrual counter. Returns the amount minted this call.
func GetReward(cur realm) uint64 {
	addr := unsafe.PreviousRealm().Address().String()
	acc := accrue(addr)
	claimed := acc.reward
	acc.reward = 0
	acc.minted += claimed
	chain.Emit("RewardPaid", "addr", addr, "amount", strconv.FormatUint(claimed, 10))
	return claimed
}

// --- read-only ------------------------------------------------------------

// Earned reports the rewards currently owed to `addr` (accrued but unminted),
// projected to the current block without mutating any state.
func Earned(addr address) uint64 {
	v := accounts.Get(addr.String())
	if v == nil {
		return 0
	}
	acc := v.(*account)
	elapsed := currentBlock() - lastUpdateBlock
	rpt := computeRewardPerToken(rewardPerTokenAcc, rewardPerBlock, elapsed, totalStaked)
	return computeEarned(acc.staked, rpt, acc.rewardPaid, acc.reward)
}

// StakedOf reports the current staked balance of `addr`.
func StakedOf(addr address) uint64 {
	if v := accounts.Get(addr.String()); v != nil {
		return v.(*account).staked
	}
	return 0
}

// Render renders pool stats and a stakers table.
func Render(path string) string {
	out := "# Staking Rewards\n\n"
	out += "Simplified Synthetix-style staking (accounting-only, no coin transfer).\n\n"
	out += "- **Total staked:** " + strconv.FormatUint(totalStaked, 10) + "\n"
	out += "- **Reward rate:** " + strconv.FormatUint(rewardPerBlock, 10) + " / block (split across stakers)\n"
	out += "- **Block height:** " + strconv.FormatUint(currentBlock(), 10) + "\n\n"

	if accounts.Size() == 0 {
		out += "_No stakers yet. Call `Stake(amount)` to join._\n"
		return out
	}

	out += "## Stakers\n\n"
	out += "| Address | Staked | Earned (pending) | Minted |\n"
	out += "|---|---|---|---|\n"

	elapsed := currentBlock() - lastUpdateBlock
	rpt := computeRewardPerToken(rewardPerTokenAcc, rewardPerBlock, elapsed, totalStaked)
	accounts.Iterate("", "", func(key string, value interface{}) bool {
		acc := value.(*account)
		earned := computeEarned(acc.staked, rpt, acc.rewardPaid, acc.reward)
		out += "| " + key +
			" | " + strconv.FormatUint(acc.staked, 10) +
			" | " + strconv.FormatUint(earned, 10) +
			" | " + strconv.FormatUint(acc.minted, 10) + " |\n"
		return false
	})
	return out
}

// Package merkledrop is an idiomatic gno.land port of the classic Solidity
// MerkleDistributor airdrop (Uniswap's contract, OpenZeppelin's MerkleProof).
//
// A fixed merkleRoot commits to a set of (address, amount) allocations. A
// recipient proves membership by supplying the sibling hashes on the path from
// their leaf up to the root. Each address may claim exactly once.
//
// Leaf and node hashing use crypto/sha256 (available in the gno stdlib), the
// same primitive Solidity distributors use via keccak — here sha256 keeps the
// off-chain tree builder trivially reproducible. Internal nodes hash the two
// children in sorted order (the OpenZeppelin "commutative" scheme), so proofs
// carry no left/right flags.
//
//	leaf   = sha256(addr.String() + "|" + amount)
//	node   = sha256(min(a,b) || max(a,b))
//
// Balances are pure accounting (uint64); no real coin moves — there is no
// msg.value on gno, so this models the allocation ledger only.
package merkledrop

import (
	"bytes"
	"crypto/sha256"
	"encoding/hex"
	"strconv"
	"strings"

	"chain"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

// merkleRoot commits to the airdrop allocation set. Generated off-chain with
// the exact scheme above over the four example recipients in README.md.
const merkleRoot = "0d00b73577019dc92924f0ae001d3e1839d51fb358adda2ad1510c39eb82b13f"

// claimed maps claimer address string -> claimed amount (uint64).
var claimed avl.Tree

// totalClaimed is the running sum of all claimed allocations.
var totalClaimed uint64

// leaf computes the tree leaf for an (address, amount) allocation.
func leaf(claimer address, amount uint64) []byte {
	data := claimer.String() + "|" + strconv.FormatUint(amount, 10)
	h := sha256.Sum256([]byte(data))
	return h[:]
}

// hashPair hashes two nodes in sorted order (commutative), so the proof does
// not need to encode child positions.
func hashPair(a, b []byte) []byte {
	var d []byte
	if bytes.Compare(a, b) <= 0 {
		d = append(append(d, a...), b...)
	} else {
		d = append(append(d, b...), a...)
	}
	h := sha256.Sum256(d)
	return h[:]
}

// parseProof splits a comma-separated list of hex hashes into raw 32-byte
// nodes, panicking on any malformed element.
func parseProof(proof string) [][]byte {
	proof = strings.TrimSpace(proof)
	if proof == "" {
		return nil
	}
	parts := strings.Split(proof, ",")
	out := make([][]byte, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		raw, err := hex.DecodeString(p)
		if err != nil {
			panic("merkledrop: bad proof hash: " + p)
		}
		if len(raw) != sha256.Size {
			panic("merkledrop: proof hash must be 32 bytes: " + p)
		}
		out = append(out, raw)
	}
	return out
}

// computeRoot walks the proof from the given leaf up to a candidate root and
// returns its hex encoding.
func computeRoot(leafHash []byte, proof [][]byte) string {
	node := leafHash
	for _, sib := range proof {
		node = hashPair(node, sib)
	}
	return hex.EncodeToString(node)
}

// Verify reports whether (claimer, amount, proof) resolves to merkleRoot. Pure
// and read-only — safe to call from tests and Render.
func Verify(claimer address, amount uint64, proof string) bool {
	got := computeRoot(leaf(claimer, amount), parseProof(proof))
	return got == merkleRoot
}

// AmountClaimed returns how much the address has already claimed (0 if none).
func AmountClaimed(claimer address) uint64 {
	if !claimed.Has(claimer.String()) {
		return 0
	}
	return claimed.Get(claimer.String()).(uint64)
}

// HasClaimed reports whether the address already claimed.
func HasClaimed(claimer address) bool {
	return claimed.Has(claimer.String())
}

// Claim proves the caller is entitled to `amount` via `proof` (comma-separated
// hex sibling hashes) and marks the allocation claimed. Panics on a bad proof
// or a double claim. Mirrors MerkleDistributor.claim (msg.sender is the caller).
func Claim(cur realm, amount uint64, proof string) {
	caller := unsafe.PreviousRealm().Address()
	if HasClaimed(caller) {
		panic("merkledrop: already claimed")
	}
	if !Verify(caller, amount, proof) {
		panic("merkledrop: invalid proof")
	}
	claimed.Set(caller.String(), amount)
	totalClaimed += amount

	chain.Emit("Claimed",
		"account", caller.String(),
		"amount", strconv.FormatUint(amount, 10),
	)
}

// Render shows the committed root, aggregate stats, and the list of claimers.
func Render(path string) string {
	var b strings.Builder
	b.WriteString("# MerkleDrop\n\n")
	b.WriteString("A fixed Merkle root gates a one-per-address airdrop. Prove your allocation with `Claim(amount, proof)`.\n\n")

	b.WriteString("## Root\n\n")
	b.WriteString("`" + merkleRoot + "`\n\n")

	b.WriteString("## Stats\n\n")
	b.WriteString("- Distinct claimers: " + strconv.Itoa(claimed.Size()) + "\n")
	b.WriteString("- Total claimed: " + strconv.FormatUint(totalClaimed, 10) + "\n\n")

	b.WriteString("## Claimers\n\n")
	if claimed.Size() == 0 {
		b.WriteString("_No claims yet._\n")
		return b.String()
	}
	b.WriteString("| Address | Amount |\n|---|---|\n")
	claimed.Iterate("", "", func(key string, value interface{}) bool {
		b.WriteString("| " + key + " | " + strconv.FormatUint(value.(uint64), 10) + " |\n")
		return false
	})
	return b.String()
}

// Package englishauction is an idiomatic gno.land port of the classic Solidity
// English (ascending-bid) auction. Anyone can Start an auction for a named item
// with a duration in blocks; bidders call Bid with a strictly increasing amount.
// The previous highest bid becomes refundable (claim it with Withdraw). After
// the auction's end height anyone may call End, awarding the item to the highest
// bidder. Auctions and pending refunds live in ordered avl trees so Render can
// iterate deterministically.
package englishauction

import (
	"strconv"

	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

// Auction is a single ascending-bid auction.
type Auction struct {
	ID            int64
	Seller        address
	Item          string
	EndHeight     int64
	HighestBid    uint64
	HighestBidder address
	Ended         bool
}

var (
	auctions avl.Tree // key(id) -> *Auction
	pending  avl.Tree // "<id>:<addr>" -> uint64 refundable amount
	nextID   int64    = 1
)

// key formats an id into a zero-padded, lexicographically-sortable string.
func key(id int64) string {
	s := strconv.FormatInt(id, 10)
	for len(s) < 12 {
		s = "0" + s
	}
	return s
}

// pendKey formats the refund key for a given auction id and bidder.
func pendKey(id int64, bidder address) string {
	return key(id) + ":" + bidder.String()
}

// Start opens a new auction for `item` running for `durationBlocks` blocks from
// the current height. The caller becomes the seller. Returns the auction id.
func Start(cur realm, item string, durationBlocks int64) int64 {
	if item == "" {
		panic("englishauction: item must not be empty")
	}
	if durationBlocks <= 0 {
		panic("englishauction: duration must be > 0 blocks")
	}
	seller := unsafe.PreviousRealm().Address()
	id := nextID
	nextID++

	a := &Auction{
		ID:        id,
		Seller:    seller,
		Item:      item,
		EndHeight: runtime.ChainHeight() + durationBlocks,
	}
	auctions.Set(key(id), a)

	chain.Emit("Start",
		"id", strconv.FormatInt(id, 10),
		"seller", seller.String(),
		"item", item,
		"endHeight", strconv.FormatInt(a.EndHeight, 10),
	)
	return id
}

// Bid places a bid of `amount` on auction `id`. It must strictly exceed the
// current highest bid. The displaced highest bid becomes refundable to its
// bidder via Withdraw.
func Bid(cur realm, id int64, amount uint64) {
	a := mustGet(id)
	if a.Ended || runtime.ChainHeight() >= a.EndHeight {
		panic("englishauction: auction has ended")
	}
	if amount <= a.HighestBid {
		panic("englishauction: bid must strictly exceed current highest")
	}
	bidder := unsafe.PreviousRealm().Address()
	if bidder == a.Seller {
		panic("englishauction: seller cannot bid")
	}

	// The prior top bid becomes refundable (accumulate in case of repeats).
	if a.HighestBid > 0 {
		pk := pendKey(id, a.HighestBidder)
		pending.Set(pk, pendingOf(id, a.HighestBidder)+a.HighestBid)
	}

	a.HighestBid = amount
	a.HighestBidder = bidder

	chain.Emit("Bid",
		"id", strconv.FormatInt(id, 10),
		"bidder", bidder.String(),
		"amount", strconv.FormatUint(amount, 10),
	)
}

// Withdraw refunds the caller's accumulated displaced bids for auction `id`.
// Returns the amount refunded (0 if nothing pending).
func Withdraw(cur realm, id int64) uint64 {
	mustGet(id) // ensure auction exists
	caller := unsafe.PreviousRealm().Address()
	amount := pendingOf(id, caller)
	if amount == 0 {
		return 0
	}
	pending.Remove(pendKey(id, caller))
	chain.Emit("Withdraw",
		"id", strconv.FormatInt(id, 10),
		"bidder", caller.String(),
		"amount", strconv.FormatUint(amount, 10),
	)
	return amount
}

// End closes auction `id` once its end height is reached, awarding the item to
// the highest bidder (if any). Anyone may call it.
func End(cur realm, id int64) {
	a := mustGet(id)
	if a.Ended {
		panic("englishauction: auction already ended")
	}
	if runtime.ChainHeight() < a.EndHeight {
		panic("englishauction: auction not yet over")
	}
	a.Ended = true

	chain.Emit("End",
		"id", strconv.FormatInt(id, 10),
		"winner", a.HighestBidder.String(),
		"amount", strconv.FormatUint(a.HighestBid, 10),
	)
}

// --- read-only helpers (safe from tests and Render) ---

// mustGet returns the auction for `id`, panicking if it does not exist.
func mustGet(id int64) *Auction {
	v := auctions.Get(key(id))
	if v == nil {
		panic("englishauction: no such auction")
	}
	return v.(*Auction)
}

// pendingOf returns the refundable amount owed to `bidder` for auction `id`.
func pendingOf(id int64, bidder address) uint64 {
	v := pending.Get(pendKey(id, bidder))
	if v == nil {
		return 0
	}
	return v.(uint64)
}

// blocksLeft returns how many blocks remain before `a` can be ended (0 if the
// end height has been reached).
func blocksLeft(a *Auction, height int64) int64 {
	if height >= a.EndHeight {
		return 0
	}
	return a.EndHeight - height
}

// hasWinner reports whether the auction received at least one bid.
func hasWinner(a *Auction) bool {
	return a.HighestBid > 0
}

// Render lists every auction with item, top bid + bidder, time left, and winner.
func Render(path string) string {
	out := "# English Auction\n\n"
	out += "Ascending-bid auctions. Start one, outbid others, and End it after "
	out += "its block deadline to award the item to the top bidder.\n\n"

	if auctions.Size() == 0 {
		out += "_No auctions yet. Call `Start` to open one._\n"
		return out
	}

	height := runtime.ChainHeight()
	out += "_Current block height: " + strconv.FormatInt(height, 10) + "_\n\n"
	out += "| ID | Item | Highest Bid | Bidder | Status | Winner |\n"
	out += "|---:|------|------------:|--------|--------|--------|\n"

	auctions.Iterate("", "", func(_ string, v interface{}) bool {
		a := v.(*Auction)

		bidStr := "—"
		bidderStr := "—"
		if hasWinner(a) {
			bidStr = strconv.FormatUint(a.HighestBid, 10)
			bidderStr = "`" + a.HighestBidder.String() + "`"
		}

		status := ""
		winner := "—"
		switch {
		case a.Ended:
			status = "ended"
			if hasWinner(a) {
				winner = "`" + a.HighestBidder.String() + "`"
			} else {
				winner = "no bids"
			}
		case height >= a.EndHeight:
			status = "awaiting End"
		default:
			status = strconv.FormatInt(blocksLeft(a, height), 10) + " blocks left"
		}

		out += "| " + strconv.FormatInt(a.ID, 10) + " | " + a.Item + " | " +
			bidStr + " | " + bidderStr + " | " + status + " | " + winner + " |\n"
		return false
	})
	return out
}

// Package wrapped is an accounting-only port of Wrapped Ether (WETH).
//
// The canonical WETH contract lets anyone lock native ETH and mint a 1:1
// ERC-20 representation (and burn it back). On gno.land / topaz there is no
// msg.value / payable, so there is NO real coin transfer here: Deposit and
// Withdraw are pure accounting operations that model the wrap/unwrap. Balances
// and totalSupply are plain uint64 ledgers kept in an avl.Tree.
package wrapped

import (
	"strconv"

	"chain"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

// balances maps owner address (string) -> wrapped balance (uint64).
var (
	balances    avl.Tree
	totalSupply uint64
)

// Deposit wraps `amount` units of the (notional) native coin, crediting the
// caller's wrapped balance and the global totalSupply. Accounting only: no real
// coin ever moves — it models locking native funds to mint the wrapped token.
func Deposit(cur realm, amount uint64) {
	if amount == 0 {
		panic("wrapped: deposit amount must be > 0")
	}
	owner := unsafe.PreviousRealm().Address()
	setBalance(owner, balanceOf(owner)+amount)
	totalSupply += amount
	chain.Emit("Deposit", "dst", owner.String(), "wad", strconv.FormatUint(amount, 10))
}

// Withdraw unwraps `amount` units, burning them from the caller's balance and
// from totalSupply. Panics if the caller lacks the balance.
func Withdraw(cur realm, amount uint64) {
	if amount == 0 {
		panic("wrapped: withdraw amount must be > 0")
	}
	owner := unsafe.PreviousRealm().Address()
	bal := balanceOf(owner)
	if bal < amount {
		panic("wrapped: insufficient balance")
	}
	setBalance(owner, bal-amount)
	totalSupply -= amount
	chain.Emit("Withdrawal", "src", owner.String(), "wad", strconv.FormatUint(amount, 10))
}

// Transfer moves `amount` wrapped units from the caller to `to`.
func Transfer(cur realm, to address, amount uint64) {
	if amount == 0 {
		panic("wrapped: transfer amount must be > 0")
	}
	from := unsafe.PreviousRealm().Address()
	if from == to {
		panic("wrapped: cannot transfer to self")
	}
	fromBal := balanceOf(from)
	if fromBal < amount {
		panic("wrapped: insufficient balance")
	}
	setBalance(from, fromBal-amount)
	setBalance(to, balanceOf(to)+amount)
	chain.Emit("Transfer", "src", from.String(), "dst", to.String(), "wad", strconv.FormatUint(amount, 10))
}

// balanceOf returns the wrapped balance of `owner` (read-only, not crossing).
func balanceOf(owner address) uint64 {
	v := balances.Get(owner.String())
	if v == nil {
		return 0
	}
	return v.(uint64)
}

// BalanceOf is the exported read-only accessor for a single owner.
func BalanceOf(owner address) uint64 { return balanceOf(owner) }

// TotalSupply returns the total amount of wrapped units in existence.
func TotalSupply() uint64 { return totalSupply }

func setBalance(owner address, amount uint64) {
	if amount == 0 {
		balances.Remove(owner.String())
		return
	}
	balances.Set(owner.String(), amount)
}

// ---- pure/read-only helpers (unit-tested) ----

// canDebit reports whether `bal` can cover `amount` for a burn/transfer.
func canDebit(bal, amount uint64) bool {
	return amount > 0 && bal >= amount
}

// formatUnits renders a raw uint64 amount as a decimal string.
func formatUnits(n uint64) string {
	return strconv.FormatUint(n, 10)
}

// Render shows the total supply and a table of non-zero balances.
func Render(path string) string {
	out := "# Wrapped (WETH-style, accounting-only)\n\n"
	out += "Deposit mints wrapped units, Withdraw burns them. No real coins move — this is a pure ledger.\n\n"
	out += "**Total supply:** " + formatUnits(totalSupply) + "\n\n"

	if balances.Size() == 0 {
		out += "_No balances yet. Call `Deposit` to wrap some units._\n"
		return out
	}

	out += "| Owner | Balance |\n|---|---:|\n"
	balances.Iterate("", "", func(key string, value interface{}) bool {
		out += "| `" + key + "` | " + formatUnits(value.(uint64)) + " |\n"
		return false
	})
	return out
}

// Package governor is a simplified on-chain governance realm inspired by
// OpenZeppelin's Governor. Anyone may open a proposal; every address gets a
// single equally-weighted vote (1 address = 1 vote); a proposal succeeds when
// its voting deadline has passed and the "for" tally strictly beats "against".
package governor

import (
	"strconv"
	"strings"

	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

// votingPeriod is the number of blocks a proposal stays open for voting.
const votingPeriod = int64(100)

// Vote support values.
const (
	VoteAgainst = 0
	VoteFor     = 1
	VoteAbstain = 2
)

// Proposal state values.
const (
	StateActive    = "Active"
	StateSucceeded = "Succeeded"
	StateDefeated  = "Defeated"
	StateExecuted  = "Executed"
)

// Proposal is a single governance proposal.
type Proposal struct {
	ID             int64
	Proposer       address
	Description    string
	SnapshotHeight int64
	Deadline       int64
	For            int64
	Against        int64
	Abstain        int64
	Executed       bool
	votes          *avl.Tree // voter address (string) -> support (int)
}

var (
	proposals  = avl.NewTree() // id (zero-padded string) -> *Proposal
	nextID     = int64(1)
	totalCount int64
)

// Propose opens a new proposal and returns its id. The snapshot height and
// deadline are recorded from the current chain height.
func Propose(cur realm, description string) int64 {
	if strings.TrimSpace(description) == "" {
		panic("governor: empty description")
	}
	proposer := unsafe.PreviousRealm().Address()
	h := runtime.ChainHeight()
	id := nextID
	nextID++
	totalCount++

	p := &Proposal{
		ID:             id,
		Proposer:       proposer,
		Description:    description,
		SnapshotHeight: h,
		Deadline:       h + votingPeriod,
		votes:          avl.NewTree(),
	}
	proposals.Set(idKey(id), p)

	chain.Emit(
		"ProposalCreated",
		"id", strconv.FormatInt(id, 10),
		"proposer", proposer.String(),
		"deadline", strconv.FormatInt(p.Deadline, 10),
	)
	return id
}

// CastVote records one vote for the caller on proposal id. support is
// 0=against, 1=for, 2=abstain. One address may vote at most once per proposal,
// and voting is only allowed while the proposal is Active.
func CastVote(cur realm, id int64, support int) {
	p := mustGet(id)
	if computeState(p, runtime.ChainHeight()) != StateActive {
		panic("governor: voting closed")
	}
	if support < VoteAgainst || support > VoteAbstain {
		panic("governor: invalid support value")
	}
	voter := unsafe.PreviousRealm().Address()
	if p.votes.Has(voter.String()) {
		panic("governor: already voted")
	}
	p.votes.Set(voter.String(), support)

	switch support {
	case VoteFor:
		p.For++
	case VoteAgainst:
		p.Against++
	default:
		p.Abstain++
	}

	chain.Emit(
		"VoteCast",
		"id", strconv.FormatInt(id, 10),
		"voter", voter.String(),
		"support", strconv.Itoa(support),
	)
}

// Execute marks a Succeeded proposal as executed. It panics unless the
// proposal has reached the Succeeded state.
func Execute(cur realm, id int64) {
	p := mustGet(id)
	if computeState(p, runtime.ChainHeight()) != StateSucceeded {
		panic("governor: proposal not in Succeeded state")
	}
	p.Executed = true
	chain.Emit("ProposalExecuted", "id", strconv.FormatInt(id, 10))
}

// State returns the current lifecycle state of proposal id.
func State(id int64) string {
	return computeState(mustGet(id), runtime.ChainHeight())
}

// computeState is the pure state machine: it decides the state of p at chain
// height h. Kept free of globals so it is unit-testable.
func computeState(p *Proposal, h int64) string {
	if p.Executed {
		return StateExecuted
	}
	if h < p.Deadline {
		return StateActive
	}
	if p.For > p.Against {
		return StateSucceeded
	}
	return StateDefeated
}

func mustGet(id int64) *Proposal {
	key := idKey(id)
	if !proposals.Has(key) {
		panic("governor: unknown proposal " + strconv.FormatInt(id, 10))
	}
	return proposals.Get(key).(*Proposal)
}

// idKey returns a zero-padded, lexicographically-sortable key for an id so the
// avl tree iterates proposals in numeric order.
func idKey(id int64) string {
	s := strconv.FormatInt(id, 10)
	const width = 12
	if len(s) >= width {
		return s
	}
	return strings.Repeat("0", width-len(s)) + s
}

// bar renders a proportional ▓░ progress bar of fixed width.
func bar(value, total int64, width int) string {
	if width <= 0 {
		return ""
	}
	filled := 0
	if total > 0 {
		filled = int((value*int64(width) + total/2) / total)
		if filled > width {
			filled = width
		}
	}
	return strings.Repeat("▓", filled) + strings.Repeat("░", width-filled)
}

// Render lists all proposals with their tallies and states as Markdown.
func Render(path string) string {
	var b strings.Builder
	b.WriteString("# 🏛️ Governor\n\n")
	b.WriteString("Simplified on-chain governance — 1 address = 1 vote, ")
	b.WriteString("voting period of " + strconv.FormatInt(votingPeriod, 10) + " blocks.\n\n")

	h := runtime.ChainHeight()
	b.WriteString("Current chain height: **" + strconv.FormatInt(h, 10) + "**\n\n")

	if totalCount == 0 {
		b.WriteString("_No proposals yet. Call `Propose` to create one._\n")
		return b.String()
	}

	b.WriteString("Total proposals: **" + strconv.FormatInt(totalCount, 10) + "**\n\n")

	proposals.Iterate("", "", func(_ string, v interface{}) bool {
		p := v.(*Proposal)
		state := computeState(p, h)
		total := p.For + p.Against + p.Abstain

		b.WriteString("---\n\n")
		b.WriteString("## #" + strconv.FormatInt(p.ID, 10) + " · " + state + "\n\n")
		b.WriteString("> " + p.Description + "\n\n")
		b.WriteString("- Proposer: `" + p.Proposer.String() + "`\n")
		b.WriteString("- Snapshot height: " + strconv.FormatInt(p.SnapshotHeight, 10) + "\n")
		b.WriteString("- Deadline height: " + strconv.FormatInt(p.Deadline, 10))
		if state == StateActive {
			b.WriteString(" (" + strconv.FormatInt(p.Deadline-h, 10) + " blocks left)")
		}
		b.WriteString("\n\n")

		b.WriteString("| Choice | Votes | Tally |\n")
		b.WriteString("|---|---|---|\n")
		b.WriteString("| For | " + strconv.FormatInt(p.For, 10) + " | `" + bar(p.For, total, 20) + "` |\n")
		b.WriteString("| Against | " + strconv.FormatInt(p.Against, 10) + " | `" + bar(p.Against, total, 20) + "` |\n")
		b.WriteString("| Abstain | " + strconv.FormatInt(p.Abstain, 10) + " | `" + bar(p.Abstain, total, 20) + "` |\n\n")

		return false
	})

	return b.String()
}

// Package lottery is an idiomatic gno.land port of the classic Solidity
// Lottery contract. Players Enter the current round (one entry per address per
// round). Once a round has at least two entrants, anyone may DrawWinner: a
// winner is picked deterministically from the block height (ChainHeight() %
// len(entrants), over the deterministically-sorted entrant set), recorded in
// the winners history, and a fresh round is opened.
//
// There is no real randomness on-chain, so "random" selection is derived from
// the block height — the same source Solidity ports use via block.number.
package lottery

import (
	"strconv"
	"strings"

	"chain"
	"chain/runtime"
	"chain/runtime/unsafe"

	"gno.land/p/nt/avl/v0"
)

// round is the current (open) round number, 1-based.
var round int = 1

// entrants holds the current round's players: key = address string, value =
// the address. Iteration is deterministic (sorted by key), which makes winner
// selection reproducible.
var entrants avl.Tree

// winners records past rounds: key = zero-padded round number (for ordered
// iteration), value = *winnerRecord.
var winners avl.Tree

type winnerRecord struct {
	Round       int
	Winner      address
	NumEntrants int
	Height      int64
}

// winnerKey zero-pads the round number so avl iteration yields chronological
// order for up to 10^9 rounds.
func winnerKey(r int) string {
	s := strconv.Itoa(r)
	for len(s) < 9 {
		s = "0" + s
	}
	return s
}

// pickIndex derives the winning entrant index from the block height. Panics if
// there are no entrants. Pure helper (deterministic, no state) — safe to test.
func pickIndex(height int64, n int) int {
	if n <= 0 {
		panic("lottery: no entrants to draw from")
	}
	i := height % int64(n)
	if i < 0 {
		i += int64(n)
	}
	return int(i)
}

// Enter adds the caller to the current round's entrants. Each address may only
// enter a given round once; a duplicate entry panics.
func Enter(cur realm) {
	player := unsafe.PreviousRealm().Address()
	key := player.String()
	if entrants.Has(key) {
		panic("lottery: already entered this round")
	}
	entrants.Set(key, player)

	chain.Emit("Enter",
		"round", strconv.Itoa(round),
		"player", key,
		"entrants", strconv.Itoa(entrants.Size()),
	)
}

// DrawWinner closes the current round, provided it has at least two entrants,
// picks the winner deterministically from the block height, records it, and
// opens a new empty round.
func DrawWinner(cur realm) address {
	n := entrants.Size()
	if n < 2 {
		panic("lottery: need at least 2 entrants to draw")
	}

	height := runtime.ChainHeight()
	idx := pickIndex(height, n)

	var winner address
	i := 0
	entrants.Iterate("", "", func(_ string, value interface{}) bool {
		if i == idx {
			winner = value.(address)
			return true // stop
		}
		i++
		return false
	})

	rec := &winnerRecord{
		Round:       round,
		Winner:      winner,
		NumEntrants: n,
		Height:      height,
	}
	winners.Set(winnerKey(round), rec)

	chain.Emit("DrawWinner",
		"round", strconv.Itoa(round),
		"winner", winner.String(),
		"entrants", strconv.Itoa(n),
		"height", strconv.FormatInt(height, 10),
	)

	// Open a fresh round.
	round++
	entrants = avl.Tree{}

	return winner
}

// CurrentRound returns the currently open round number.
func CurrentRound() int {
	return round
}

// NumEntrants returns how many players have entered the current round.
func NumEntrants() int {
	return entrants.Size()
}

// HasEntered reports whether addr is in the current round.
func HasEntered(addr address) bool {
	return entrants.Has(addr.String())
}

// Render shows the current round, its entrants, and the winners history.
func Render(path string) string {
	var b strings.Builder
	b.WriteString("# Lottery\n\n")
	b.WriteString("Enter the open round, then anyone can draw once it has ")
	b.WriteString("at least two players. The winner is picked from the block ")
	b.WriteString("height and a new round opens automatically.\n\n")

	b.WriteString("## Round " + strconv.Itoa(round) + " (open)\n\n")
	if entrants.Size() == 0 {
		b.WriteString("_No entrants yet. Call `Enter` to join._\n\n")
	} else {
		b.WriteString(strconv.Itoa(entrants.Size()) + " entrant(s):\n\n")
		entrants.Iterate("", "", func(key string, _ interface{}) bool {
			b.WriteString("- `" + key + "`\n")
			return false
		})
		b.WriteString("\n")
		if entrants.Size() < 2 {
			b.WriteString("_Need at least 2 entrants before a draw._\n\n")
		} else {
			b.WriteString("_Ready to draw: call `DrawWinner`._\n\n")
		}
	}

	b.WriteString("## Past winners\n\n")
	if winners.Size() == 0 {
		b.WriteString("_No rounds drawn yet._\n")
	} else {
		b.WriteString("| Round | Winner | Entrants | Block Height |\n")
		b.WriteString("|---|---|---|---|\n")
		winners.Iterate("", "", func(_ string, value interface{}) bool {
			r := value.(*winnerRecord)
			b.WriteString("| " + strconv.Itoa(r.Round) +
				" | `" + r.Winner.String() + "`" +
				" | " + strconv.Itoa(r.NumEntrants) +
				" | " + strconv.FormatInt(r.Height, 10) + " |\n")
			return false
		})
	}

	return b.String()
}

